// Package posthog provides PostHog error tracking integration for the API server.
// It wraps the posthog-go SDK with graceful degradation — when POSTHOG_API_KEY
// is absent, a no-op client is used and no tracking occurs.
package posthog

import (
	"context"
	"log/slog"
	"time"

	ph "github.com/posthog/posthog-go"
)

// Config holds PostHog configuration parsed from environment variables.
type Config struct {
	APIKey string
	Host   string
}

// Enabled reports whether PostHog is configured (API key is present).
func (c Config) Enabled() bool {
	return c.APIKey != ""
}

// Client wraps a posthog.Client with convenience methods for exception capture.
// When PostHog is not configured, all methods are safe no-ops.
type Client struct {
	inner   ph.Client
	enabled bool
}

// New creates a PostHog client from the given config. If the API key is absent,
// returns a no-op client that silently discards all events.
func New(cfg Config) (*Client, error) {
	if !cfg.Enabled() {
		return &Client{enabled: false}, nil
	}

	host := cfg.Host
	if host == "" {
		host = "https://us.i.posthog.com"
	}

	inner, err := ph.NewWithConfig(cfg.APIKey, ph.Config{
		Endpoint: host,
	})
	if err != nil {
		return nil, err
	}

	return &Client{inner: inner, enabled: true}, nil
}

// Enabled reports whether this client is actively sending events.
func (c *Client) Enabled() bool {
	return c != nil && c.enabled
}

// CaptureException enqueues an exception event to PostHog.
// Safe to call on a nil or disabled client (no-op).
func (c *Client) CaptureException(distinctID, title, description string) error {
	if !c.Enabled() {
		return nil
	}
	return c.inner.Enqueue(ph.Capture{
		DistinctId: distinctID,
		Event:      "$exception",
		Timestamp:  time.Now(),
		Properties: ph.NewProperties().
			Set("$exception_type", title).
			Set("$exception_message", description),
	})
}

// Enqueue delegates to the underlying PostHog client. No-op when disabled.
func (c *Client) Enqueue(msg ph.Message) error {
	if !c.Enabled() {
		return nil
	}
	return c.inner.Enqueue(msg)
}

// Close flushes pending events and closes the client.
// Safe to call on a nil or disabled client.
func (c *Client) Close() error {
	if !c.Enabled() {
		return nil
	}
	return c.inner.Close()
}

// CloseWithContext flushes pending events with a deadline.
// Safe to call on a nil or disabled client.
func (c *Client) CloseWithContext(ctx context.Context) error {
	if !c.Enabled() {
		return nil
	}
	return c.inner.CloseWithContext(ctx)
}

// Inner returns the underlying posthog.Client, or nil if disabled.
// Use this for advanced operations not covered by the wrapper.
func (c *Client) Inner() ph.Client {
	if !c.Enabled() {
		return nil
	}
	return c.inner
}

// WrapSlogHandler wraps a base slog.Handler with PostHog's SlogCaptureHandler.
// Logs at Warn level and above are automatically captured as PostHog exceptions.
// If the client is disabled, returns the base handler unchanged.
func (c *Client) WrapSlogHandler(base slog.Handler) slog.Handler {
	if !c.Enabled() {
		return base
	}
	return ph.NewSlogCaptureHandler(
		base,
		c.inner,
		ph.WithMinCaptureLevel(slog.LevelWarn),
	)
}
